SELECT C.SEMESTRE FROM CALC_HORA_AULA_MEDIA AS C JOIN SERVIDOR AS S ON S.PK_SIAPE = C.SIAPE WHERE C.ANO = 2020 AND UPPER(C.SIGLA_CAMPUS) = 'FOR' AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%matem%') AND LOWER(S.CONTRATO) = LOWER('efetivos') GROUP BY C.SEMESTRE HAVING COUNT(DISTINCT C.SIAPE) = 3 ORDER BY C.SEMESTRE